  5→//! Wrap command - mark a pace complete with automated commit
  6→//!
  7→//! Stages all changes, generates a commit message with Claude,
  8→//! and transitions the pace state to complete with chalk marker.
  9→
 10→use std::path::PathBuf;
 11→use std::io::Write;
 12→use std::fmt::Write as FmtWrite;
 13→
 14→use crate::jjrf_favor::{jjrf_Coronet as Coronet};
 15→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_TallyArgs as LibTallyArgs, jjrg_PaceState};
 16→use crate::jjrn_notch::{jjrn_ChalkMarker, jjrn_format_notch_prefix, jjrn_format_chalk_message};
 17→
 18→/// Arguments for jjx_wrap command
 19→#[derive(clap::Args, Debug)]
 20→pub struct jjrx_WrapArgs {
 21→    /// Pace identity (Coronet)
 22→    pub coronet: String,
 23→
 24→    /// Size limit in bytes (overrides default 50KB guard)
 25→    #[arg(long)]
 26→    pub size_limit: Option<u64>,
 27→}
 28→
 29→/// Helper to get pace silks or return default message
 30→fn get_pace_silks_or_default(gallops: &Gallops, firemark_key: &str, coronet_key: &str) -> String {
 31→    gallops.heats
 32→        .get(firemark_key)
 33→        .and_then(|heat| heat.paces.get(coronet_key))
 34→        .and_then(|pace| pace.tacks.first())
 35→        .map(|tack| format!("pace {} complete", tack.silks))
 36→        .unwrap_or_else(|| "pace complete".to_string())
 37→}
 38→
 39→/// Execute wrap command - mark pace complete with commit
 40→///
 41→/// Stages all changes, checks size, generates commit message using Claude,
 42→/// creates the work commit, then transitions pace to complete state with
 43→/// chalk marker commit.
 44→///
 45→/// Returns exit code (0 for success, non-zero for failure).
 46→pub fn zjjrx_run_wrap(args: jjrx_WrapArgs, summary: Option<String>) -> (i32, String) {
 47→    let mut buf = String::new();
 48→
 49→    // Parse coronet
 50→    let coronet = match Coronet::jjrf_parse(&args.coronet) {
 51→        Ok(c) => c,
 52→        Err(e) => {
 53→            jjbuf!(buf, "jjx_wrap: error: {}", e);
 54→            return (1, buf);
 55→        }
 56→    };
 57→
 58→    let stdin_summary = summary;
 59→
 60→    // Acquire commit lock
 61→    let _lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 62→        Ok(l) => l,
 63→        Err(e) => {
 64→            jjbuf!(buf, "jjx_wrap: error: {}", e);
 65→            return (1, buf);
 66→        }
 67→    };
 68→
 69→    // Stage all changes
 70→    let add_output = match vvc::vvce_git_command(&["add", "-A"])
 71→        .output()
 72→    {
 73→        Ok(o) => o,
 74→        Err(e) => {
 75→            jjbuf!(buf, "jjx_wrap: error: failed to run git add: {}", e);
 76→            return (1, buf);
 77→        }
 78→    };
 79→
 80→    if !add_output.status.success() {
 81→        jjbuf!(buf, "jjx_wrap: error: git add failed");
 82→        return (1, buf);
 83→    }
 84→
 85→    // Size guard check
 86→    let size_limit = args.size_limit.unwrap_or(50000); // 50KB default
 87→    let diff_output = match vvc::vvce_git_command(&["diff", "--cached", "--stat"])
 88→        .output()
 89→    {
 90→        Ok(o) => o,
 91→        Err(e) => {
 92→            jjbuf!(buf, "jjx_wrap: error: failed to run git diff: {}", e);
 93→            return (1, buf);
 94→        }
 95→    };
 96→
 97→    if !diff_output.status.success() {
 98→        jjbuf!(buf, "jjx_wrap: error: git diff failed");
 99→        return (1, buf);
100→    }
101→
102→    // Parse size from last line of --stat output (format: "N files changed, M insertions(+), K deletions(-)")
103→    // Better size check: get actual staged content size
104→    let numstat_output = match vvc::vvce_git_command(&["diff", "--cached", "--numstat"])
105→        .output()
106→    {
107→        Ok(o) => o,
108→        Err(e) => {
109→            jjbuf!(buf, "jjx_wrap: error: failed to run git diff --numstat: {}", e);
110→            return (1, buf);
111→        }
112→    };
113→
114→    if !numstat_output.status.success() {
115→        jjbuf!(buf, "jjx_wrap: error: git diff --numstat failed");
116→        return (1, buf);
117→    }
118→
119→    let numstat_str = String::from_utf8_lossy(&numstat_output.stdout);
120→    let mut total_size: u64 = 0;
121→    for line in numstat_str.lines() {
122→        let parts: Vec<&str> = line.split_whitespace().collect();
123→        if parts.len() >= 2 {
124→            // Format: added\tdeleted\tfilename
125→            if let Ok(added) = parts[0].parse::<u64>() {
126→                total_size += added;
127→            }
128→            if let Ok(deleted) = parts[1].parse::<u64>() {
129→                total_size += deleted;
130→            }
131→        }
132→    }
133→
134→    if total_size > size_limit {
135→        jjbuf!(buf, "jjx_wrap: error: staged changes exceed size limit ({} > {} bytes)", total_size, size_limit);
136→        // Lock released automatically by Drop
137→        return (2, buf);
138→    }
139→
140→    // Check if there are staged changes to commit
141→    let has_staged_changes = !numstat_str.trim().is_empty();
142→
143→    // Only generate commit message and commit if there are staged changes
144→    let commit_hash = if has_staged_changes {
145→        // Generate commit message using Claude CLI
146→        let diff_content = match vvc::vvce_git_command(&["diff", "--cached"])
147→            .output()
148→        {
149→            Ok(o) => o,
150→            Err(e) => {
151→                jjbuf!(buf, "jjx_wrap: error: failed to run git diff --cached: {}", e);
152→                return (1, buf);
153→            }
154→        };
155→
156→        if !diff_content.status.success() {
157→            jjbuf!(buf, "jjx_wrap: error: git diff --cached failed");
158→            return (1, buf);
159→        }
160→
161→        let mut claude_cmd = match vvc::vvce_claude_command()
162→            .args([
163→                "--print",
164→                &format!("Generate a concise commit message for this diff. The commit wraps pace {}. Output only the message, no quotes.", args.coronet)
165→            ])
166→            .stdin(std::process::Stdio::piped())
167→            .stdout(std::process::Stdio::piped())
168→            .stderr(std::process::Stdio::piped())
169→            .spawn()
170→        {
171→            Ok(c) => c,
172→            Err(e) => {
173→                jjbuf!(buf, "jjx_wrap: error: failed to spawn claude command: {}", e);
174→                return (1, buf);
175→            }
176→        };
177→
178→        // Write diff to stdin
179→        if let Some(mut stdin) = claude_cmd.stdin.take() {
180→            if let Err(e) = stdin.write_all(&diff_content.stdout) {
181→                jjbuf!(buf, "jjx_wrap: error: failed to write to claude stdin: {}", e);
182→                return (1, buf);
183→            }
184→        }
185→
186→        let claude_output = match claude_cmd.wait_with_output() {
187→            Ok(o) => o,
188→            Err(e) => {
189→                jjbuf!(buf, "jjx_wrap: error: failed to wait for claude: {}", e);
190→                return (1, buf);
191→            }
192→        };
193→
194→        if !claude_output.status.success() {
195→            jjbuf!(buf, "jjx_wrap: error: claude command failed");
196→            jjbuf!(buf, "{}", String::from_utf8_lossy(&claude_output.stderr));
197→            return (1, buf);
198→        }
199→
200→        let generated_message = String::from_utf8_lossy(&claude_output.stdout).trim().to_string();
201→
202→        // Commit with git directly (already staged via git add -A)
203→        let prefix = jjrn_format_notch_prefix(&coronet);
204→        let full_message = format!("{}{}\n\nCo-Authored-By: Claude <noreply@anthropic.com>", prefix, generated_message);
205→
206→        let commit_output = match vvc::vvce_git_command(&["commit", "-m", &full_message])
207→            .output()
208→        {
209→            Ok(o) => o,
210→            Err(e) => {
211→                jjbuf!(buf, "jjx_wrap: error: failed to run git commit: {}", e);
212→                return (1, buf);
213→            }
214→        };
215→
216→        if !commit_output.status.success() {
217→            jjbuf!(buf, "jjx_wrap: error: git commit failed");
218→            jjbuf!(buf, "{}", String::from_utf8_lossy(&commit_output.stderr));
219→            return (1, buf);
220→        }
221→
222→        // Get commit hash
223→        let hash_output = match vvc::vvce_git_command(&["rev-parse", "HEAD"])
224→            .output()
225→        {
226→            Ok(o) => o,
227→            Err(e) => {
228→                jjbuf!(buf, "jjx_wrap: error: failed to get commit hash: {}", e);
229→                return (1, buf);
230→            }
231→        };
232→
233→        String::from_utf8_lossy(&hash_output.stdout).trim().to_string()
234→    } else {
235→        // No staged changes - this is valid for verification-only paces
236→        jjbuf!(buf, "jjx_wrap: no staged changes, proceeding with state transition only");
237→
238→        // Get current HEAD as reference (no new work commit created)
239→        let hash_output = match vvc::vvce_git_command(&["rev-parse", "HEAD"])
240→            .output()
241→        {
242→            Ok(o) => o,
243→            Err(e) => {
244→                jjbuf!(buf, "jjx_wrap: error: failed to get commit hash: {}", e);
245→                return (1, buf);
246→            }
247→        };
248→
249→        String::from_utf8_lossy(&hash_output.stdout).trim().to_string()
250→    };
251→
252→    // Transition pace state to complete
253→    let gallops_path = PathBuf::from(".claude/jjm/jjg_gallops.json");
254→    let mut gallops = match Gallops::jjrg_load(&gallops_path) {
255→        Ok(g) => g,
256→        Err(e) => {
257→            jjbuf!(buf, "jjx_wrap: error loading Gallops: {}", e);
258→            return (1, buf);
259→        }
260→    };
261→
262→    let tally_args = LibTallyArgs {
263→        coronet: args.coronet.clone(),
264→        state: Some(jjrg_PaceState::Complete),
265→        direction: None,
266→        text: None,
267→        silks: None,
268→    };
269→
270→    if let Err(e) = gallops.jjrg_tally(tally_args) {
271→        jjbuf!(buf, "jjx_wrap: error: {}", e);
272→        return (1, buf);
273→    }
274→
275→    // Save gallops
276→    if let Err(e) = gallops.jjrg_save(&gallops_path) {
277→        jjbuf!(buf, "jjx_wrap: error saving Gallops: {}", e);
278→        return (1, buf);
279→    }
280→
281→    // Build chalk description: use stdin if provided, else "pace {silks} complete"
282→    let firemark = coronet.jjrf_parent_firemark();
283→    let firemark_key = firemark.jjrf_display();
284→    let coronet_key = coronet.jjrf_display();
285→
286→    let chalk_description = if let Some(ref text) = stdin_summary {
287→        let trimmed = text.trim();
288→        if !trimmed.is_empty() {
289→            trimmed.to_string()
290→        } else {
291→            // Empty stdin - use default with silks
292→            get_pace_silks_or_default(&gallops, &firemark_key, &coronet_key)
293→        }
294→    } else {
295→        // No stdin - use default with silks
296→        get_pace_silks_or_default(&gallops, &firemark_key, &coronet_key)
297→    };
298→
299→    // Create W chalk marker commit with gallops state change
300→    let chalk_message = jjrn_format_chalk_message(&coronet, jjrn_ChalkMarker::Wrap, &chalk_description);
301→
302→    let chalk_commit_args = vvc::vvcm_CommitArgs {
303→        files: vec![".claude/jjm/jjg_gallops.json".to_string()],
304→        message: chalk_message,
305→        size_limit: vvc::VVCG_SIZE_LIMIT,
306→        warn_limit: vvc::VVCG_WARN_LIMIT,
307→    };
308→
309→    match vvc::machine_commit(&_lock, &chalk_commit_args) {
310→        Ok(_) => {
311→            let _ = writeln!(buf, "{}", commit_hash);
312→            let fm = coronet.jjrf_parent_firemark();
313→            let fm_key = fm.jjrf_display();
314→            let fm_str = fm.jjrf_as_str();
315→
316→            // Lookahead: find next actionable pace in this heat
317→            let next_pace_info = gallops.heats.get(&fm_key).and_then(|heat| {
318→                heat.order.iter().find_map(|c| {
319→                    heat.paces.get(c.as_str()).and_then(|pace| {
320→                        pace.tacks.first().and_then(|tack| {
321→                            match tack.state {
322→                                jjrg_PaceState::Rough | jjrg_PaceState::Bridled => {
323→                                    Some((c.clone(), tack.silks.clone()))
324→                                }
325→                                _ => None,
326→                            }
327→                        })
328→                    })
329→                })
330→            });
331→
332→            jjbuf!(buf, "");
333→            match next_pace_info {
334→                Some((next_coronet, next_silks)) => {
335→                    jjbuf!(buf, "AGENT_RESPONSE: \u{20a2}{} wrapped. Next: {} (\u{20a2}{}) \u{2014} `/clear` then `/jjc-heat-mount {}`",
336→                        args.coronet, next_silks, next_coronet, fm_str);
337→                }
338→                None => {
339→                    jjbuf!(buf, "AGENT_RESPONSE: \u{20a2}{} wrapped. All paces complete \u{2014} `/clear` then `/jjc-heat-retire {}`",
340→                        args.coronet, fm_str);
341→                }
342→            }
343→            (0, buf)
344→        }
345→        Err(e) => {
346→            jjbuf!(buf, "jjx_wrap: error: chalk commit failed: {}", e);
347→            jjbuf!(buf, "jjx_wrap: warning: gallops state updated but not committed");
348→            (1, buf)
349→        }
350→    }
351→    // lock released here
352→}
353→

