  5→//! Notch command - JJ-aware commit with heat/pace context prefix
  6→//!
  7→//! This module handles the jjx_notch command which performs a staged commit
  8→//! with heat/pace context prefix. It accepts explicit file list and generates
  9→//! a JJ context-aware commit message.
 10→
 11→use clap::Args;
 12→use std::collections::HashSet;
 13→
 14→use crate::jjrf_favor::{jjrf_Coronet as Coronet, jjrf_Firemark as Firemark, JJRF_FIREMARK_PREFIX, JJRF_CORONET_PREFIX};
 15→use crate::jjrn_notch::{jjrn_format_notch_prefix, JJRN_COMMIT_PREFIX};
 16→
 17→/// Arguments for jjx_notch command
 18→#[derive(Args, Debug)]
 19→pub struct jjrnc_NotchArgs {
 20→    /// Identity: Coronet (5-char, pace-affiliated) or Firemark (2-char, heat-only)
 21→    pub identity: String,
 22→
 23→    /// Files to commit (required, at least one)
 24→    #[arg(required = true)]
 25→    pub files: Vec<String>,
 26→
 27→    /// Size limit in bytes (overrides default 50KB guard)
 28→    #[arg(long)]
 29→    pub size_limit: Option<u64>,
 30→
 31→    /// User-provided commit message intent (overrides haiku-generated message)
 32→    #[arg(long)]
 33→    pub intent: Option<String>,
 34→}
 35→
 36→/// Run the notch command
 37→///
 38→/// Stages specified files and commits with JJ-aware prefix.
 39→/// Supports both pace-affiliated (Coronet) and heat-only (Firemark) commits.
 40→pub fn jjrnc_run_notch(args: jjrnc_NotchArgs) -> (i32, String) {
 41→    let mut buf = String::new();
 42→
 43→    // Require non-empty files list
 44→    if args.files.is_empty() {
 45→        jjbuf!(buf, "jjx_notch: error: at least one file required");
 46→        return (1, buf);
 47→    }
 48→
 49→    // Check each file either exists on disk or is tracked by git (for deletions)
 50→    for file in &args.files {
 51→        let path_exists = std::path::Path::new(file).exists();
 52→
 53→        // If file doesn't exist on disk, check if it's tracked by git
 54→        if !path_exists {
 55→            let git_ls_output = match vvc::vvce_git_command(&["ls-files", "--error-unmatch", file])
 56→                .output()
 57→            {
 58→                Ok(o) => o,
 59→                Err(e) => {
 60→                    jjbuf!(buf, "jjx_notch: error: failed to check git tracking: {}", e);
 61→                    return (1, buf);
 62→                }
 63→            };
 64→
 65→            // If git ls-files fails, check if it's a staged deletion
 66→            if !git_ls_output.status.success() {
 67→                let git_diff_output = match vvc::vvce_git_command(&["diff", "--cached", "--name-only", "--diff-filter=D", "--", file])
 68→                    .output()
 69→                {
 70→                    Ok(o) => o,
 71→                    Err(e) => {
 72→                        jjbuf!(buf, "jjx_notch: error: failed to check staged deletion: {}", e);
 73→                        return (1, buf);
 74→                    }
 75→                };
 76→
 77→                // If diff output is non-empty, file is a staged deletion - accept it
 78→                let is_staged_deletion = git_diff_output.status.success()
 79→                    && !git_diff_output.stdout.is_empty();
 80→
 81→                if !is_staged_deletion {
 82→                    jjbuf!(buf, "jjx_notch: error: file does not exist and is not tracked by git: {}", file);
 83→                    return (1, buf);
 84→                }
 85→            }
 86→        }
 87→    }
 88→
 89→    // Parse identity - support both Coronet (5 chars) and Firemark (2 chars)
 90→    let identity = args.identity.strip_prefix(JJRF_CORONET_PREFIX).or_else(|| args.identity.strip_prefix(JJRF_FIREMARK_PREFIX)).unwrap_or(&args.identity);
 91→
 92→    let message = if identity.len() == 5 {
 93→        // Coronet - pace-affiliated commit
 94→        let coronet = match Coronet::jjrf_parse(&args.identity) {
 95→            Ok(c) => c,
 96→            Err(e) => {
 97→                jjbuf!(buf, "jjx_notch: error: {}", e);
 98→                return (1, buf);
 99→            }
100→        };
101→        jjrn_format_notch_prefix(&coronet)
102→    } else if identity.len() == 2 {
103→        // Firemark - heat-only commit
104→        let firemark = match Firemark::jjrf_parse(&args.identity) {
105→            Ok(fm) => fm,
106→            Err(e) => {
107→                jjbuf!(buf, "jjx_notch: error: {}", e);
108→                return (1, buf);
109→            }
110→        };
111→        let hallmark = vvc::vvcc_get_hallmark();
112→        let identity_str = format!("{}{}", JJRF_FIREMARK_PREFIX, firemark.jjrf_as_str());
113→        vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity_str, "n", "", None)
114→    } else {
115→        jjbuf!(buf, "jjx_notch: error: identity must be Coronet (5 chars) or Firemark (2 chars), got {} chars", identity.len());
116→        return (1, buf);
117→    };
118→
119→    // Warn about uncommitted changes outside the file list
120→    let output = match vvc::vvce_git_command(&["status", "--porcelain"])
121→        .output()
122→    {
123→        Ok(o) => o,
124→        Err(e) => {
125→            jjbuf!(buf, "jjx_notch: error: failed to run git status: {}", e);
126→            return (1, buf);
127→        }
128→    };
129→
130→    if !output.status.success() {
131→        jjbuf!(buf, "jjx_notch: error: git status failed");
132→        return (1, buf);
133→    }
134→
135→    let status_output = String::from_utf8_lossy(&output.stdout);
136→    let files_set: HashSet<_> = args.files.iter().map(|s| s.as_str()).collect();
137→    let mut warnings = Vec::new();
138→
139→    for line in status_output.lines() {
140→        if line.len() < 4 {
141→            continue;
142→        }
143→        // Parse git status --porcelain format: "XY filename"
144→        let filepath = &line[3..];
145→        if !files_set.contains(filepath) {
146→            warnings.push(format!("  {}", line));
147→        }
148→    }
149→
150→    if !warnings.is_empty() {
151→        jjbuf!(buf, "warning: uncommitted changes outside file list:");
152→        for warning in warnings {
153→            jjbuf!(buf, "{}", warning);
154→        }
155→    }
156→
157→    // Stage only the specified files
158→    let mut git_add = vvc::vvce_git_command(&["add"]);
159→    for file in &args.files {
160→        git_add.arg(file);
161→    }
162→
163→    let add_output = match git_add.output() {
164→        Ok(o) => o,
165→        Err(e) => {
166→            jjbuf!(buf, "jjx_notch: error: failed to run git add: {}", e);
167→            return (1, buf);
168→        }
169→    };
170→
171→    if !add_output.status.success() {
172→        jjbuf!(buf, "jjx_notch: error: git add failed");
173→        return (1, buf);
174→    }
175→
176→    // Commit using vvc with the generated message prefix
177→    // If --intent provided, use it as the message; otherwise let haiku generate it
178→    let commit_args = if let Some(intent) = args.intent {
179→        vvc::vvcc_CommitArgs {
180→            prefix: None,
181→            message: Some(format!("{}{}", message, intent)),
182→            allow_empty: false,
183→            no_stage: true,  // We already staged above
184→            size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
185→            warn_limit: vvc::VVCG_WARN_LIMIT,
186→        }
187→    } else {
188→        vvc::vvcc_CommitArgs {
189→            prefix: Some(message),
190→            message: None,
191→            allow_empty: false,
192→            no_stage: true,  // We already staged above
193→            size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
194→            warn_limit: vvc::VVCG_WARN_LIMIT,
195→        }
196→    };
197→
198→    let rc = vvc::commit(&commit_args);
199→    (rc, buf)
200→}
201→

