  5→//! Saddle command - Return context needed to saddle up on a Heat
  6→
  7→use std::fmt::Write;
  8→use std::fs;
  9→use std::path::PathBuf;
 10→
 11→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 12→use crate::jjrf_favor::jjrf_Coronet as Coronet;
 13→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
 14→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
 15→use crate::jjrs_steeplechase::{jjrs_get_entries, jjrs_ReinArgs};
 16→use crate::jjrq_query::jjrq_resolve_default_heat;
 17→use crate::jjrpd_parade::{jjrpd_write_file_bitmap, jjrpd_write_commit_swimlanes};
 18→
 19→/// Arguments for saddle command
 20→#[derive(clap::Args, Debug)]
 21→pub struct jjrsd_SaddleArgs {
 22→    /// Path to the Gallops JSON file
 23→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 24→    pub file: PathBuf,
 25→
 26→    /// Target Heat identity (Firemark) or Pace identity (Coronet). If omitted, uses first racing heat.
 27→    pub firemark: Option<String>,
 28→}
 29→
 30→/// Run the saddle command - return Heat context
 31→pub async fn jjrsd_run_saddle(args: jjrsd_SaddleArgs) -> (i32, String) {
 32→    let mut buf = String::new();
 33→    let gallops = match Gallops::jjrg_load(&args.file) {
 34→        Ok(g) => g,
 35→        Err(e) => {
 36→            jjbuf!(buf, "jjx_orient: error: {}", e);
 37→            return (1, buf);
 38→        }
 39→    };
 40→
 41→    // Collect racing heats in heat_order priority sequence for display table
 42→    {
 43→        let racing_heats: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heat_order.iter()
 44→            .filter_map(|fm| gallops.heats.get(fm).map(|h| (fm, h)))
 45→            .filter(|(_, heat)| heat.status == HeatStatus::Racing)
 46→            .collect();
 47→
 48→        if !racing_heats.is_empty() {
 49→            let mut table = jjrp_Table::jjrp_new(vec![
 50→                jjrp_Column::new("₣Fire", jjrp_Align::Left),
 51→                jjrp_Column::new("Silks", jjrp_Align::Left),
 52→                jjrp_Column::new("Status", jjrp_Align::Left),
 53→                jjrp_Column::new("Done", jjrp_Align::Right),
 54→                jjrp_Column::new("Total", jjrp_Align::Right),
 55→            ]);
 56→
 57→            // Measure all rows to compute column widths
 58→            for (key, heat) in &racing_heats {
 59→                let defined_count = heat.paces.values().filter(|pace| {
 60→                    if let Some(tack) = pace.tacks.first() {
 61→                        tack.state != PaceState::Abandoned
 62→                    } else {
 63→                        true
 64→                    }
 65→                }).count();
 66→
 67→                let completed_count = heat.paces.values().filter(|pace| {
 68→                    if let Some(tack) = pace.tacks.first() {
 69→                        tack.state == PaceState::Complete
 70→                    } else {
 71→                        false
 72→                    }
 73→                }).count();
 74→
 75→                table.jjrp_measure(&[
 76→                    key,
 77→                    &heat.silks,
 78→                    "racing",
 79→                    &completed_count.to_string(),
 80→                    &defined_count.to_string(),
 81→                ]);
 82→            }
 83→
 84→            // Print header and separator
 85→            let _ = writeln!(buf, "Racing-heats:");
 86→            table.jjrp_write_header(&mut buf);
 87→            table.jjrp_write_separator(&mut buf);
 88→
 89→            // Print data rows
 90→            for (key, heat) in &racing_heats {
 91→                let defined_count = heat.paces.values().filter(|pace| {
 92→                    if let Some(tack) = pace.tacks.first() {
 93→                        tack.state != PaceState::Abandoned
 94→                    } else {
 95→                        true
 96→                    }
 97→                }).count();
 98→
 99→                let completed_count = heat.paces.values().filter(|pace| {
100→                    if let Some(tack) = pace.tacks.first() {
101→                        tack.state == PaceState::Complete
102→                    } else {
103→                        false
104→                    }
105→                }).count();
106→
107→                table.jjrp_write_row(&mut buf, &[
108→                    key,
109→                    &heat.silks,
110→                    "racing",
111→                    &completed_count.to_string(),
112→                    &defined_count.to_string(),
113→                ]);
114→            }
115→
116→            let _ = writeln!(buf);
117→        }
118→    }
119→
120→    // Resolve firemark: use provided value or auto-select first racing heat
121→    let firemark_str = match args.firemark {
122→        Some(fm) => fm,
123→        None => {
124→            match jjrq_resolve_default_heat(&gallops) {
125→                Ok(fm) => fm,
126→                Err(e) => {
127→                    jjbuf!(buf, "jjx_orient: error: {}", e);
128→                    return (1, buf);
129→                }
130→            }
131→        }
132→    };
133→
134→    // Detect if input is a coronet (5 chars) or firemark (2 chars)
135→    // Strip any prefix first: ₣ (U+20A3) or ₢ (U+20A2)
136→    let stripped_input = firemark_str
137→        .trim_start_matches('₣')
138→        .trim_start_matches('₢');
139→
140→    let target_coronet = if stripped_input.len() == 5 {
141→        // It's a coronet - parse to get parent firemark
142→        let coronet = match Coronet::jjrf_parse(&firemark_str) {
143→            Ok(c) => c,
144→            Err(e) => {
145→                jjbuf!(buf, "jjx_orient: error: {}", e);
146→                return (1, buf);
147→            }
148→        };
149→        Some(coronet)
150→    } else if stripped_input.len() == 2 {
151→        // It's a firemark - existing behavior
152→        None
153→    } else {
154→        jjbuf!(buf, "jjx_orient: error: Invalid argument '{}' (must be 2-char firemark or 5-char coronet)", firemark_str);
155→        return (1, buf);
156→    };
157→
158→    // Extract firemark (either directly provided or from coronet parent)
159→    let firemark = if let Some(ref coronet) = target_coronet {
160→        coronet.jjrf_parent_firemark()
161→    } else {
162→        match Firemark::jjrf_parse(&firemark_str) {
163→            Ok(fm) => fm,
164→            Err(e) => {
165→                jjbuf!(buf, "jjx_orient: error: {}", e);
166→                return (1, buf);
167→            }
168→        }
169→    };
170→
171→    let heat_key = firemark.jjrf_display();
172→    let heat = match gallops.heats.get(&heat_key) {
173→        Some(h) => h,
174→        None => {
175→            jjbuf!(buf, "jjx_orient: error: Heat '{}' not found", heat_key);
176→            return (1, buf);
177→        }
178→    };
179→
180→    // Check if heat is stabled (cannot saddle stabled heat)
181→    if heat.status == HeatStatus::Stabled {
182→        jjbuf!(buf, "jjx_orient: error: Cannot saddle stabled heat '{}'", heat_key);
183→        return (1, buf);
184→    }
185→
186→    // Read paddock file content
187→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
188→        Ok(content) => content,
189→        Err(e) => {
190→            jjbuf!(buf, "jjx_orient: error reading paddock file '{}': {}", heat.paddock_file, e);
191→            return (1, buf);
192→        }
193→    };
194→
195→    // Get recent steeplechase entries
196→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
197→        firemark: firemark.jjrf_as_str().to_string(),
198→        limit: 10,
199→    }).unwrap_or_default();
200→
201→    // Find pace to display
202→    let mut pace_coronet: Option<String> = None;
203→    let mut pace_silks: Option<String> = None;
204→    let mut pace_state: Option<String> = None;
205→    let mut spec: Option<String> = None;
206→    let mut direction: Option<String> = None;
207→
208→    if let Some(ref coronet) = target_coronet {
209→        // Specific coronet requested - look it up directly
210→        let coronet_key = coronet.jjrf_display();
211→
212→        match heat.paces.get(&coronet_key) {
213→            Some(pace) => {
214→                if let Some(tack) = pace.tacks.first() {
215→                    match tack.state {
216→                        PaceState::Rough | PaceState::Bridled => {
217→                            pace_coronet = Some(coronet_key.clone());
218→                            pace_silks = Some(tack.silks.clone());
219→                            pace_state = Some(match tack.state {
220→                                PaceState::Rough => "rough".to_string(),
221→                                PaceState::Bridled => "bridled".to_string(),
222→                                _ => unreachable!(),
223→                            });
224→                            spec = Some(tack.text.clone());
225→                            if tack.state == PaceState::Bridled {
226→                                direction = tack.direction.clone();
227→                            }
228→                        }
229→                        PaceState::Complete => {
230→                            jjbuf!(buf, "jjx_orient: error: Pace '{}' is already complete", coronet_key);
231→                            return (1, buf);
232→                        }
233→                        PaceState::Abandoned => {
234→                            jjbuf!(buf, "jjx_orient: error: Pace '{}' is abandoned", coronet_key);
235→                            return (1, buf);
236→                        }
237→                        _ => {
238→                            jjbuf!(buf, "jjx_orient: error: Pace '{}' has invalid state", coronet_key);
239→                            return (1, buf);
240→                        }
241→                    }
242→                } else {
243→                    jjbuf!(buf, "jjx_orient: error: Pace '{}' has no tacks", coronet_key);
244→                    return (1, buf);
245→                }
246→            }
247→            None => {
248→                jjbuf!(buf, "jjx_orient: error: Pace '{}' not found in heat '{}'", coronet_key, heat_key);
249→                return (1, buf);
250→            }
251→        }
252→    } else {
253→        // Find first actionable pace (rough or bridled)
254→        for coronet_key in &heat.order {
255→            if let Some(pace) = heat.paces.get(coronet_key) {
256→                if let Some(tack) = pace.tacks.first() {
257→                    match tack.state {
258→                        PaceState::Rough | PaceState::Bridled => {
259→                            pace_coronet = Some(coronet_key.clone());
260→                            pace_silks = Some(tack.silks.clone());
261→                            pace_state = Some(match tack.state {
262→                                PaceState::Rough => "rough".to_string(),
263→                                PaceState::Bridled => "bridled".to_string(),
264→                                _ => unreachable!(),
265→                            });
266→                            spec = Some(tack.text.clone());
267→                            if tack.state == PaceState::Bridled {
268→                                direction = tack.direction.clone();
269→                            }
270→                            break;
271→                        }
272→                        _ => continue,
273→                    }
274→                }
275→            }
276→        }
277→    }
278→
279→    // Determine heat status string
280→    let status_str = match heat.status {
281→        HeatStatus::Racing => "racing",
282→        HeatStatus::Stabled => "stabled",
283→        HeatStatus::Retired => "retired",
284→    };
285→
286→    // Output plain text format
287→    let _ = writeln!(buf, "Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
288→    let _ = writeln!(buf, "Paddock: {}", heat.paddock_file);
289→    let _ = writeln!(buf);
290→    let _ = writeln!(buf, "Paddock-content:");
291→    for line in paddock_content.lines() {
292→        let _ = writeln!(buf, "  {}", line);
293→    }
294→    let _ = writeln!(buf);
295→
296→    if let Some(coronet) = pace_coronet {
297→        if let Some(silks) = pace_silks {
298→            if let Some(state) = pace_state {
299→                let _ = writeln!(buf, "Next: {} ({}) [{}]", silks, coronet, state);
300→                let _ = writeln!(buf);
301→                if let Some(spec_text) = spec {
302→                    let _ = writeln!(buf, "Docket:");
303→                    for line in spec_text.lines() {
304→                        let _ = writeln!(buf, "  {}", line);
305→                    }
306→                    let _ = writeln!(buf);
307→                }
308→                if let Some(dir_text) = direction {
309→                    let _ = writeln!(buf, "Warrant:");
310→                    for line in dir_text.lines() {
311→                        let _ = writeln!(buf, "  {}", line);
312→                    }
313→                    let _ = writeln!(buf);
314→                }
315→                jjbuf!(buf, "");
316→                if state == "bridled" {
317→                    jjbuf!(buf, "Recommended: /jjc-heat-mount {} to execute", firemark.jjrf_as_str());
318→                } else {
319→                    jjbuf!(buf, "Recommended: /jjc-pace-bridle {} or /jjc-heat-mount {}", coronet, firemark.jjrf_as_str());
320→                }
321→            }
322→        }
323→    }
324→
325→    // Output recent work table
326→    // Filter entries to only show action codes 'n' (notch), 'A' (approach), 'd' (discussion)
327→    let filtered_work: Vec<_> = recent_work.iter().filter(|entry| {
328→        if let Some(ref action) = entry.action {
329→            action == "n" || action == "A" || action == "d"
330→        } else {
331→            false
332→        }
333→    }).collect();
334→
335→    if !filtered_work.is_empty() {
336→        let _ = writeln!(buf, "Recent-work:");
337→
338→        let mut table = jjrp_Table::jjrp_new(vec![
339→            jjrp_Column::new("Commit", jjrp_Align::Left),
340→            jjrp_Column::new("Identity", jjrp_Align::Left),
341→            jjrp_Column::new("Subject", jjrp_Align::Left),
342→        ]);
343→
344→        // Measure all rows to compute column widths
345→        for entry in &filtered_work {
346→            let identity_str = if let Some(ref coronet) = entry.coronet {
347→                coronet.clone()
348→            } else {
349→                heat_key.clone()
350→            };
351→            table.jjrp_measure(&[
352→                &entry.commit,
353→                &identity_str,
354→                &entry.subject,
355→            ]);
356→        }
357→
358→        // Print header and separator
359→        table.jjrp_write_header(&mut buf);
360→        table.jjrp_write_separator(&mut buf);
361→
362→        // Print data rows
363→        for entry in &filtered_work {
364→            let identity_str = if let Some(ref coronet) = entry.coronet {
365→                coronet.clone()
366→            } else {
367→                heat_key.clone()
368→            };
369→            table.jjrp_write_row(&mut buf, &[
370→                &entry.commit,
371→                &identity_str,
372→                &entry.subject,
373→            ]);
374→        }
375→    }
376→
377→    // Always show file-touch bitmap and commit swim lanes after recent work
378→    jjrpd_write_file_bitmap(&mut buf, &firemark, heat);
379→    jjrpd_write_commit_swimlanes(&mut buf, &firemark, heat);
380→
381→    if let Err(e) = vvc::vvcp_invitatory().await {
382→        jjbuf!(buf, "jjx_orient: warning: invitatory failed: {}", e);
383→    }
384→
385→    (0, buf)
386→}
