  5→//! Saddle command - Return context needed to saddle up on a Heat
  6→
  7→use std::fs;
  8→use std::path::PathBuf;
  9→
 10→use vvc::{vvco_out, vvco_err, vvco_Output};
 11→
 12→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 13→use crate::jjrf_favor::jjrf_Coronet as Coronet;
 14→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
 15→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
 16→use crate::jjrs_steeplechase::{jjrs_get_entries, jjrs_ReinArgs};
 17→use crate::jjrq_query::jjrq_resolve_default_heat;
 18→use crate::jjrpd_parade::{jjrpd_write_file_bitmap, jjrpd_write_commit_swimlanes};
 19→
 20→/// Arguments for saddle command
 21→#[derive(clap::Args, Debug)]
 22→pub struct jjrsd_SaddleArgs {
 23→    /// Path to the Gallops JSON file
 24→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 25→    pub file: PathBuf,
 26→
 27→    /// Target Heat identity (Firemark) or Pace identity (Coronet). If omitted, uses first racing heat.
 28→    pub firemark: Option<String>,
 29→}
 30→
 31→/// Run the saddle command - return Heat context
 32→pub async fn jjrsd_run_saddle(args: jjrsd_SaddleArgs) -> (i32, String) {
 33→    let mut output = vvco_Output::buffer();
 34→    let gallops = match Gallops::jjrg_load(&args.file) {
 35→        Ok(g) => g,
 36→        Err(e) => {
 37→            jjbuf!(buf, "jjx_orient: error: {}", e);
 38→            return (1, output.vvco_finish());
 39→        }
 40→    };
 41→
 42→    // Collect racing heats in heat_order priority sequence for display table
 43→    {
 44→        let racing_heats: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heat_order.iter()
 45→            .filter_map(|fm| gallops.heats.get(fm).map(|h| (fm, h)))
 46→            .filter(|(_, heat)| heat.status == HeatStatus::Racing)
 47→            .collect();
 48→
 49→        if !racing_heats.is_empty() {
 50→            let mut table = jjrp_Table::jjrp_new(vec![
 51→                jjrp_Column::new("₣Fire", jjrp_Align::Left),
 52→                jjrp_Column::new("Silks", jjrp_Align::Left),
 53→                jjrp_Column::new("Status", jjrp_Align::Left),
 54→                jjrp_Column::new("Done", jjrp_Align::Right),
 55→                jjrp_Column::new("Total", jjrp_Align::Right),
 56→            ]);
 57→
 58→            // Measure all rows to compute column widths
 59→            for (key, heat) in &racing_heats {
 60→                let defined_count = heat.paces.values().filter(|pace| {
 61→                    if let Some(tack) = pace.tacks.first() {
 62→                        tack.state != PaceState::Abandoned
 63→                    } else {
 64→                        true
 65→                    }
 66→                }).count();
 67→
 68→                let completed_count = heat.paces.values().filter(|pace| {
 69→                    if let Some(tack) = pace.tacks.first() {
 70→                        tack.state == PaceState::Complete
 71→                    } else {
 72→                        false
 73→                    }
 74→                }).count();
 75→
 76→                table.jjrp_measure(&[
 77→                    key,
 78→                    &heat.silks,
 79→                    "racing",
 80→                    &completed_count.to_string(),
 81→                    &defined_count.to_string(),
 82→                ]);
 83→            }
 84→
 85→            // Print header and separator
 86→            let _ = writeln!(buf, "Racing-heats:");
 87→            table.jjrp_write_header(&mut buf);
 88→            table.jjrp_write_separator(&mut buf);
 89→
 90→            // Print data rows
 91→            for (key, heat) in &racing_heats {
 92→                let defined_count = heat.paces.values().filter(|pace| {
 93→                    if let Some(tack) = pace.tacks.first() {
 94→                        tack.state != PaceState::Abandoned
 95→                    } else {
 96→                        true
 97→                    }
 98→                }).count();
 99→
100→                let completed_count = heat.paces.values().filter(|pace| {
101→                    if let Some(tack) = pace.tacks.first() {
102→                        tack.state == PaceState::Complete
103→                    } else {
104→                        false
105→                    }
106→                }).count();
107→
108→                table.jjrp_write_row(&mut buf, &[
109→                    key,
110→                    &heat.silks,
111→                    "racing",
112→                    &completed_count.to_string(),
113→                    &defined_count.to_string(),
114→                ]);
115→            }
116→
117→            let _ = writeln!(buf);
118→        }
119→    }
120→
121→    // Resolve firemark: use provided value or auto-select first racing heat
122→    let firemark_str = match args.firemark {
123→        Some(fm) => fm,
124→        None => {
125→            match jjrq_resolve_default_heat(&gallops) {
126→                Ok(fm) => fm,
127→                Err(e) => {
128→                    jjbuf!(buf, "jjx_orient: error: {}", e);
129→                    return (1, output.vvco_finish());
130→                }
131→            }
132→        }
133→    };
134→
135→    // Detect if input is a coronet (5 chars) or firemark (2 chars)
136→    // Strip any prefix first: ₣ (U+20A3) or ₢ (U+20A2)
137→    let stripped_input = firemark_str
138→        .trim_start_matches('₣')
139→        .trim_start_matches('₢');
140→
141→    let target_coronet = if stripped_input.len() == 5 {
142→        // It's a coronet - parse to get parent firemark
143→        let coronet = match Coronet::jjrf_parse(&firemark_str) {
144→            Ok(c) => c,
145→            Err(e) => {
146→                jjbuf!(buf, "jjx_orient: error: {}", e);
147→                return (1, output.vvco_finish());
148→            }
149→        };
150→        Some(coronet)
151→    } else if stripped_input.len() == 2 {
152→        // It's a firemark - existing behavior
153→        None
154→    } else {
155→        jjbuf!(buf, "jjx_orient: error: Invalid argument '{}' (must be 2-char firemark or 5-char coronet)", firemark_str);
156→        return (1, output.vvco_finish());
157→    };
158→
159→    // Extract firemark (either directly provided or from coronet parent)
160→    let firemark = if let Some(ref coronet) = target_coronet {
161→        coronet.jjrf_parent_firemark()
162→    } else {
163→        match Firemark::jjrf_parse(&firemark_str) {
164→            Ok(fm) => fm,
165→            Err(e) => {
166→                jjbuf!(buf, "jjx_orient: error: {}", e);
167→                return (1, output.vvco_finish());
168→            }
169→        }
170→    };
171→
172→    let heat_key = firemark.jjrf_display();
173→    let heat = match gallops.heats.get(&heat_key) {
174→        Some(h) => h,
175→        None => {
176→            jjbuf!(buf, "jjx_orient: error: Heat '{}' not found", heat_key);
177→            return (1, output.vvco_finish());
178→        }
179→    };
180→
181→    // Check if heat is stabled (cannot saddle stabled heat)
182→    if heat.status == HeatStatus::Stabled {
183→        jjbuf!(buf, "jjx_orient: error: Cannot saddle stabled heat '{}'", heat_key);
184→        return (1, output.vvco_finish());
185→    }
186→
187→    // Read paddock file content
188→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
189→        Ok(content) => content,
190→        Err(e) => {
191→            jjbuf!(buf, "jjx_orient: error reading paddock file '{}': {}", heat.paddock_file, e);
192→            return (1, output.vvco_finish());
193→        }
194→    };
195→
196→    // Get recent steeplechase entries
197→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
198→        firemark: firemark.jjrf_as_str().to_string(),
199→        limit: 10,
200→    }).unwrap_or_default();
201→
202→    // Find pace to display
203→    let mut pace_coronet: Option<String> = None;
204→    let mut pace_silks: Option<String> = None;
205→    let mut pace_state: Option<String> = None;
206→    let mut spec: Option<String> = None;
207→    let mut direction: Option<String> = None;
208→
209→    if let Some(ref coronet) = target_coronet {
210→        // Specific coronet requested - look it up directly
211→        let coronet_key = coronet.jjrf_display();
212→
213→        match heat.paces.get(&coronet_key) {
214→            Some(pace) => {
215→                if let Some(tack) = pace.tacks.first() {
216→                    match tack.state {
217→                        PaceState::Rough | PaceState::Bridled => {
218→                            pace_coronet = Some(coronet_key.clone());
219→                            pace_silks = Some(tack.silks.clone());
220→                            pace_state = Some(match tack.state {
221→                                PaceState::Rough => "rough".to_string(),
222→                                PaceState::Bridled => "bridled".to_string(),
223→                                _ => unreachable!(),
224→                            });
225→                            spec = Some(tack.text.clone());
226→                            if tack.state == PaceState::Bridled {
227→                                direction = tack.direction.clone();
228→                            }
229→                        }
230→                        PaceState::Complete => {
231→                            jjbuf!(buf, "jjx_orient: error: Pace '{}' is already complete", coronet_key);
232→                            return (1, output.vvco_finish());
233→                        }
234→                        PaceState::Abandoned => {
235→                            jjbuf!(buf, "jjx_orient: error: Pace '{}' is abandoned", coronet_key);
236→                            return (1, output.vvco_finish());
237→                        }
238→                        _ => {
239→                            jjbuf!(buf, "jjx_orient: error: Pace '{}' has invalid state", coronet_key);
240→                            return (1, output.vvco_finish());
241→                        }
242→                    }
243→                } else {
244→                    jjbuf!(buf, "jjx_orient: error: Pace '{}' has no tacks", coronet_key);
245→                    return (1, output.vvco_finish());
246→                }
247→            }
248→            None => {
249→                jjbuf!(buf, "jjx_orient: error: Pace '{}' not found in heat '{}'", coronet_key, heat_key);
250→                return (1, output.vvco_finish());
251→            }
252→        }
253→    } else {
254→        // Find first actionable pace (rough or bridled)
255→        for coronet_key in &heat.order {
256→            if let Some(pace) = heat.paces.get(coronet_key) {
257→                if let Some(tack) = pace.tacks.first() {
258→                    match tack.state {
259→                        PaceState::Rough | PaceState::Bridled => {
260→                            pace_coronet = Some(coronet_key.clone());
261→                            pace_silks = Some(tack.silks.clone());
262→                            pace_state = Some(match tack.state {
263→                                PaceState::Rough => "rough".to_string(),
264→                                PaceState::Bridled => "bridled".to_string(),
265→                                _ => unreachable!(),
266→                            });
267→                            spec = Some(tack.text.clone());
268→                            if tack.state == PaceState::Bridled {
269→                                direction = tack.direction.clone();
270→                            }
271→                            break;
272→                        }
273→                        _ => continue,
274→                    }
275→                }
276→            }
277→        }
278→    }
279→
280→    // Determine heat status string
281→    let status_str = match heat.status {
282→        HeatStatus::Racing => "racing",
283→        HeatStatus::Stabled => "stabled",
284→        HeatStatus::Retired => "retired",
285→    };
286→
287→    // Output plain text format
288→    let _ = writeln!(buf, "Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
289→    let _ = writeln!(buf, "Paddock: {}", heat.paddock_file);
290→    let _ = writeln!(buf);
291→    let _ = writeln!(buf, "Paddock-content:");
292→    for line in paddock_content.lines() {
293→        let _ = writeln!(buf, "  {}", line);
294→    }
295→    let _ = writeln!(buf);
296→
297→    if let Some(coronet) = pace_coronet {
298→        if let Some(silks) = pace_silks {
299→            if let Some(state) = pace_state {
300→                let _ = writeln!(buf, "Next: {} ({}) [{}]", silks, coronet, state);
301→                let _ = writeln!(buf);
302→                if let Some(spec_text) = spec {
303→                    let _ = writeln!(buf, "Docket:");
304→                    for line in spec_text.lines() {
305→                        let _ = writeln!(buf, "  {}", line);
306→                    }
307→                    let _ = writeln!(buf);
308→                }
309→                if let Some(dir_text) = direction {
310→                    let _ = writeln!(buf, "Warrant:");
311→                    for line in dir_text.lines() {
312→                        let _ = writeln!(buf, "  {}", line);
313→                    }
314→                    let _ = writeln!(buf);
315→                }
316→                jjbuf!(buf, "");
317→                if state == "bridled" {
318→                    jjbuf!(buf, "Recommended: /jjc-heat-mount {} to execute", firemark.jjrf_as_str());
319→                } else {
320→                    jjbuf!(buf, "Recommended: /jjc-pace-bridle {} or /jjc-heat-mount {}", coronet, firemark.jjrf_as_str());
321→                }
322→            }
323→        }
324→    }
325→
326→    // Output recent work table
327→    // Filter entries to only show action codes 'n' (notch), 'A' (approach), 'd' (discussion)
328→    let filtered_work: Vec<_> = recent_work.iter().filter(|entry| {
329→        if let Some(ref action) = entry.action {
330→            action == "n" || action == "A" || action == "d"
331→        } else {
332→            false
333→        }
334→    }).collect();
335→
336→    if !filtered_work.is_empty() {
337→        let _ = writeln!(buf, "Recent-work:");
338→
339→        let mut table = jjrp_Table::jjrp_new(vec![
340→            jjrp_Column::new("Commit", jjrp_Align::Left),
341→            jjrp_Column::new("Identity", jjrp_Align::Left),
342→            jjrp_Column::new("Subject", jjrp_Align::Left),
343→        ]);
344→
345→        // Measure all rows to compute column widths
346→        for entry in &filtered_work {
347→            let identity_str = if let Some(ref coronet) = entry.coronet {
348→                coronet.clone()
349→            } else {
350→                heat_key.clone()
351→            };
352→            table.jjrp_measure(&[
353→                &entry.commit,
354→                &identity_str,
355→                &entry.subject,
356→            ]);
357→        }
358→
359→        // Print header and separator
360→        table.jjrp_write_header(&mut buf);
361→        table.jjrp_write_separator(&mut buf);
362→
363→        // Print data rows
364→        for entry in &filtered_work {
365→            let identity_str = if let Some(ref coronet) = entry.coronet {
366→                coronet.clone()
367→            } else {
368→                heat_key.clone()
369→            };
370→            table.jjrp_write_row(&mut buf, &[
371→                &entry.commit,
372→                &identity_str,
373→                &entry.subject,
374→            ]);
375→        }
376→    }
377→
378→    // Always show file-touch bitmap and commit swim lanes after recent work
379→    jjrpd_write_file_bitmap(&mut buf, &firemark, heat);
380→    jjrpd_write_commit_swimlanes(&mut buf, &firemark, heat);
