  5→//! Wrap command - mark a pace complete with automated commit
  6→//!
  7→//! Stages all changes, generates a commit message with Claude,
  8→//! and transitions the pace state to complete with chalk marker.
  9→
 10→use std::path::PathBuf;
 11→use std::io::Write;
 12→
 13→use vvc::{vvco_out, vvco_err, vvco_Output};
 14→
 15→use crate::jjrf_favor::{jjrf_Coronet as Coronet};
 16→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_TallyArgs as LibTallyArgs, jjrg_PaceState};
 17→use crate::jjrn_notch::{jjrn_ChalkMarker, jjrn_format_notch_prefix, jjrn_format_chalk_message};
 18→
 19→/// Arguments for jjx_wrap command
 20→#[derive(clap::Args, Debug)]
 21→pub struct jjrx_WrapArgs {
 22→    /// Pace identity (Coronet)
 23→    pub coronet: String,
 24→
 25→    /// Size limit in bytes (overrides default 50KB guard)
 26→    #[arg(long)]
 27→    pub size_limit: Option<u64>,
 28→}
 29→
 30→/// Helper to get pace silks or return default message
 31→fn get_pace_silks_or_default(gallops: &Gallops, firemark_key: &str, coronet_key: &str) -> String {
 32→    gallops.heats
 33→        .get(firemark_key)
 34→        .and_then(|heat| heat.paces.get(coronet_key))
 35→        .and_then(|pace| pace.tacks.first())
 36→        .map(|tack| format!("pace {} complete", tack.silks))
 37→        .unwrap_or_else(|| "pace complete".to_string())
 38→}
 39→
 40→/// Execute wrap command - mark pace complete with commit
 41→///
 42→/// Stages all changes, checks size, generates commit message using Claude,
 43→/// creates the work commit, then transitions pace to complete state with
 44→/// chalk marker commit.
 45→///
 46→/// Returns exit code (0 for success, non-zero for failure).
 47→pub fn zjjrx_run_wrap(args: jjrx_WrapArgs, summary: Option<String>) -> (i32, String) {
 48→    let mut output = vvco_Output::buffer();
 49→
 50→    // Parse coronet
 51→    let coronet = match Coronet::jjrf_parse(&args.coronet) {
 52→        Ok(c) => c,
 53→        Err(e) => {
 54→            vvco_err!(output, "jjx_wrap: error: {}", e);
 55→            return (1, output.vvco_finish());
 56→        }
 57→    };
 58→
 59→    let stdin_summary = summary;
 60→
 61→    // Acquire commit lock
 62→    let _lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 63→        Ok(l) => l,
 64→        Err(e) => {
 65→            vvco_err!(output, "jjx_wrap: error: {}", e);
 66→            return (1, output.vvco_finish());
 67→        }
 68→    };
 69→
 70→    // Stage all changes
 71→    let add_output = match vvc::vvce_git_command(&["add", "-A"])
 72→        .output()
 73→    {
 74→        Ok(o) => o,
 75→        Err(e) => {
 76→            vvco_err!(output, "jjx_wrap: error: failed to run git add: {}", e);
 77→            return (1, output.vvco_finish());
 78→        }
 79→    };
 80→
 81→    if !add_output.status.success() {
 82→        vvco_err!(output, "jjx_wrap: error: git add failed");
 83→        return (1, output.vvco_finish());
 84→    }
 85→
 86→    // Size guard check
 87→    let size_limit = args.size_limit.unwrap_or(50000); // 50KB default
 88→    let diff_output = match vvc::vvce_git_command(&["diff", "--cached", "--stat"])
 89→        .output()
 90→    {
 91→        Ok(o) => o,
 92→        Err(e) => {
 93→            vvco_err!(output, "jjx_wrap: error: failed to run git diff: {}", e);
 94→            return (1, output.vvco_finish());
 95→        }
 96→    };
 97→
 98→    if !diff_output.status.success() {
 99→        vvco_err!(output, "jjx_wrap: error: git diff failed");
100→        return (1, output.vvco_finish());
101→    }
102→
103→    // Parse size from last line of --stat output (format: "N files changed, M insertions(+), K deletions(-)")
104→    // Better size check: get actual staged content size
105→    let numstat_output = match vvc::vvce_git_command(&["diff", "--cached", "--numstat"])
106→        .output()
107→    {
108→        Ok(o) => o,
109→        Err(e) => {
110→            vvco_err!(output, "jjx_wrap: error: failed to run git diff --numstat: {}", e);
111→            return (1, output.vvco_finish());
112→        }
113→    };
114→
115→    if !numstat_output.status.success() {
116→        vvco_err!(output, "jjx_wrap: error: git diff --numstat failed");
117→        return (1, output.vvco_finish());
118→    }
119→
120→    let numstat_str = String::from_utf8_lossy(&numstat_output.stdout);
121→    let mut total_size: u64 = 0;
122→    for line in numstat_str.lines() {
123→        let parts: Vec<&str> = line.split_whitespace().collect();
124→        if parts.len() >= 2 {
125→            // Format: added\tdeleted\tfilename
126→            if let Ok(added) = parts[0].parse::<u64>() {
127→                total_size += added;
128→            }
129→            if let Ok(deleted) = parts[1].parse::<u64>() {
130→                total_size += deleted;
131→            }
132→        }
133→    }
134→
135→    if total_size > size_limit {
136→        vvco_err!(output, "jjx_wrap: error: staged changes exceed size limit ({} > {} bytes)", total_size, size_limit);
137→        // Lock released automatically by Drop
138→        return (2, output.vvco_finish());
139→    }
140→
141→    // Check if there are staged changes to commit
142→    let has_staged_changes = !numstat_str.trim().is_empty();
143→
144→    // Only generate commit message and commit if there are staged changes
145→    let commit_hash = if has_staged_changes {
146→        // Generate commit message using Claude CLI
147→        let diff_content = match vvc::vvce_git_command(&["diff", "--cached"])
148→            .output()
149→        {
150→            Ok(o) => o,
151→            Err(e) => {
152→                vvco_err!(output, "jjx_wrap: error: failed to run git diff --cached: {}", e);
153→                return (1, output.vvco_finish());
154→            }
155→        };
156→
157→        if !diff_content.status.success() {
158→            vvco_err!(output, "jjx_wrap: error: git diff --cached failed");
159→            return (1, output.vvco_finish());
160→        }
161→
162→        let mut claude_cmd = match vvc::vvce_claude_command()
163→            .args([
164→                "--print",
165→                &format!("Generate a concise commit message for this diff. The commit wraps pace {}. Output only the message, no quotes.", args.coronet)
166→            ])
167→            .stdin(std::process::Stdio::piped())
168→            .stdout(std::process::Stdio::piped())
169→            .stderr(std::process::Stdio::piped())
170→            .spawn()
171→        {
172→            Ok(c) => c,
173→            Err(e) => {
174→                vvco_err!(output, "jjx_wrap: error: failed to spawn claude command: {}", e);
175→                return (1, output.vvco_finish());
176→            }
177→        };
178→
179→        // Write diff to stdin
180→        if let Some(mut stdin) = claude_cmd.stdin.take() {
181→            if let Err(e) = stdin.write_all(&diff_content.stdout) {
182→                vvco_err!(output, "jjx_wrap: error: failed to write to claude stdin: {}", e);
183→                return (1, output.vvco_finish());
184→            }
185→        }
186→
187→        let claude_output = match claude_cmd.wait_with_output() {
188→            Ok(o) => o,
189→            Err(e) => {
190→                vvco_err!(output, "jjx_wrap: error: failed to wait for claude: {}", e);
191→                return (1, output.vvco_finish());
192→            }
193→        };
194→
195→        if !claude_output.status.success() {
196→            vvco_err!(output, "jjx_wrap: error: claude command failed");
197→            vvco_err!(output, "{}", String::from_utf8_lossy(&claude_output.stderr));
198→            return (1, output.vvco_finish());
199→        }
200→
201→        let generated_message = String::from_utf8_lossy(&claude_output.stdout).trim().to_string();
202→
203→        // Commit with git directly (already staged via git add -A)
204→        let prefix = jjrn_format_notch_prefix(&coronet);
205→        let full_message = format!("{}{}\n\nCo-Authored-By: Claude <noreply@anthropic.com>", prefix, generated_message);
206→
207→        let commit_output = match vvc::vvce_git_command(&["commit", "-m", &full_message])
208→            .output()
209→        {
210→            Ok(o) => o,
211→            Err(e) => {
212→                vvco_err!(output, "jjx_wrap: error: failed to run git commit: {}", e);
213→                return (1, output.vvco_finish());
214→            }
215→        };
216→
217→        if !commit_output.status.success() {
218→            vvco_err!(output, "jjx_wrap: error: git commit failed");
219→            vvco_err!(output, "{}", String::from_utf8_lossy(&commit_output.stderr));
220→            return (1, output.vvco_finish());
221→        }
222→
223→        // Get commit hash
224→        let hash_output = match vvc::vvce_git_command(&["rev-parse", "HEAD"])
225→            .output()
226→        {
227→            Ok(o) => o,
228→            Err(e) => {
229→                vvco_err!(output, "jjx_wrap: error: failed to get commit hash: {}", e);
230→                return (1, output.vvco_finish());
231→            }
232→        };
233→
234→        String::from_utf8_lossy(&hash_output.stdout).trim().to_string()
235→    } else {
236→        // No staged changes - this is valid for verification-only paces
237→        vvco_out!(output, "jjx_wrap: no staged changes, proceeding with state transition only");
238→
239→        // Get current HEAD as reference (no new work commit created)
240→        let hash_output = match vvc::vvce_git_command(&["rev-parse", "HEAD"])
241→            .output()
242→        {
243→            Ok(o) => o,
244→            Err(e) => {
245→                vvco_err!(output, "jjx_wrap: error: failed to get commit hash: {}", e);
246→                return (1, output.vvco_finish());
247→            }
248→        };
249→
250→        String::from_utf8_lossy(&hash_output.stdout).trim().to_string()
251→    };
252→
253→    // Transition pace state to complete
254→    let gallops_path = PathBuf::from(".claude/jjm/jjg_gallops.json");
255→    let mut gallops = match Gallops::jjrg_load(&gallops_path) {
256→        Ok(g) => g,
257→        Err(e) => {
258→            vvco_err!(output, "jjx_wrap: error loading Gallops: {}", e);
259→            return (1, output.vvco_finish());
260→        }
261→    };
262→
263→    let tally_args = LibTallyArgs {
264→        coronet: args.coronet.clone(),
265→        state: Some(jjrg_PaceState::Complete),
266→        direction: None,
267→        text: None,
268→        silks: None,
269→    };
270→
271→    if let Err(e) = gallops.jjrg_tally(tally_args) {
272→        vvco_err!(output, "jjx_wrap: error: {}", e);
273→        return (1, output.vvco_finish());
274→    }
275→
276→    // Save gallops
277→    if let Err(e) = gallops.jjrg_save(&gallops_path) {
278→        vvco_err!(output, "jjx_wrap: error saving Gallops: {}", e);
279→        return (1, output.vvco_finish());
280→    }
281→
282→    // Build chalk description: use stdin if provided, else "pace {silks} complete"
283→    let firemark = coronet.jjrf_parent_firemark();
284→    let firemark_key = firemark.jjrf_display();
285→    let coronet_key = coronet.jjrf_display();
286→
287→    let chalk_description = if let Some(ref text) = stdin_summary {
288→        let trimmed = text.trim();
289→        if !trimmed.is_empty() {
290→            trimmed.to_string()
291→        } else {
292→            // Empty stdin - use default with silks
293→            get_pace_silks_or_default(&gallops, &firemark_key, &coronet_key)
294→        }
295→    } else {
296→        // No stdin - use default with silks
297→        get_pace_silks_or_default(&gallops, &firemark_key, &coronet_key)
298→    };
299→
300→    // Create W chalk marker commit with gallops state change
301→    let chalk_message = jjrn_format_chalk_message(&coronet, jjrn_ChalkMarker::Wrap, &chalk_description);
302→
303→    let chalk_commit_args = vvc::vvcm_CommitArgs {
304→        files: vec![".claude/jjm/jjg_gallops.json".to_string()],
305→        message: chalk_message,
306→        size_limit: vvc::VVCG_SIZE_LIMIT,
307→        warn_limit: vvc::VVCG_WARN_LIMIT,
308→    };
309→
310→    match vvc::machine_commit(&_lock, &chalk_commit_args, &mut output) {
311→        Ok(_) => {
312→            vvco_out!(output, "{}", commit_hash);
313→            let fm = coronet.jjrf_parent_firemark();
314→            let fm_key = fm.jjrf_display();
315→            let fm_str = fm.jjrf_as_str();
316→
317→            // Lookahead: find next actionable pace in this heat
318→            let next_pace_info = gallops.heats.get(&fm_key).and_then(|heat| {
319→                heat.order.iter().find_map(|c| {
320→                    heat.paces.get(c.as_str()).and_then(|pace| {
321→                        pace.tacks.first().and_then(|tack| {
322→                            match tack.state {
323→                                jjrg_PaceState::Rough | jjrg_PaceState::Bridled => {
324→                                    Some((c.clone(), tack.silks.clone()))
325→                                }
326→                                _ => None,
327→                            }
328→                        })
329→                    })
330→                })
331→            });
332→
333→            vvco_out!(output, "");
334→            match next_pace_info {
335→                Some((next_coronet, next_silks)) => {
336→                    vvco_out!(output, "AGENT_RESPONSE: \u{20a2}{} wrapped. Next: {} (\u{20a2}{}) \u{2014} `/clear` then `/jjc-heat-mount {}`",
337→                        args.coronet, next_silks, next_coronet, fm_str);
338→                }
339→                None => {
340→                    vvco_out!(output, "AGENT_RESPONSE: \u{20a2}{} wrapped. All paces complete \u{2014} `/clear` then `/jjc-heat-retire {}`",
341→                        args.coronet, fm_str);
342→                }
343→            }
344→            (0, output.vvco_finish())
345→        }
346→        Err(e) => {
347→            vvco_err!(output, "jjx_wrap: error: chalk commit failed: {}", e);
348→            vvco_err!(output, "jjx_wrap: warning: gallops state updated but not committed");
349→            (1, output.vvco_finish())
350→        }
351→    }
352→    // lock released here
353→}
