  5→//! Notch command - JJ-aware commit with heat/pace context prefix
  6→//!
  7→//! This module handles the jjx_notch command which performs a staged commit
  8→//! with heat/pace context prefix. It accepts explicit file list and generates
  9→//! a JJ context-aware commit message.
 10→
 11→use clap::Args;
 12→use std::collections::HashSet;
 13→
 14→use vvc::{vvco_out, vvco_err, vvco_Output};
 15→
 16→use crate::jjrf_favor::{jjrf_Coronet as Coronet, jjrf_Firemark as Firemark, JJRF_FIREMARK_PREFIX, JJRF_CORONET_PREFIX};
 17→use crate::jjrn_notch::{jjrn_format_notch_prefix, JJRN_COMMIT_PREFIX};
 18→
 19→/// Arguments for jjx_notch command
 20→#[derive(Args, Debug)]
 21→pub struct jjrnc_NotchArgs {
 22→    /// Identity: Coronet (5-char, pace-affiliated) or Firemark (2-char, heat-only)
 23→    pub identity: String,
 24→
 25→    /// Files to commit (required, at least one)
 26→    #[arg(required = true)]
 27→    pub files: Vec<String>,
 28→
 29→    /// Size limit in bytes (overrides default 50KB guard)
 30→    #[arg(long)]
 31→    pub size_limit: Option<u64>,
 32→
 33→    /// User-provided commit message intent (overrides haiku-generated message)
 34→    #[arg(long)]
 35→    pub intent: Option<String>,
 36→}
 37→
 38→/// Run the notch command
 39→///
 40→/// Stages specified files and commits with JJ-aware prefix.
 41→/// Supports both pace-affiliated (Coronet) and heat-only (Firemark) commits.
 42→pub fn jjrnc_run_notch(args: jjrnc_NotchArgs) -> (i32, String) {
 43→    let mut output = vvco_Output::buffer();
 44→
 45→    // Require non-empty files list
 46→    if args.files.is_empty() {
 47→        vvco_err!(output, "jjx_notch: error: at least one file required");
 48→        return (1, output.vvco_finish());
 49→    }
 50→
 51→    // Check each file either exists on disk or is tracked by git (for deletions)
 52→    for file in &args.files {
 53→        let path_exists = std::path::Path::new(file).exists();
 54→
 55→        // If file doesn't exist on disk, check if it's tracked by git
 56→        if !path_exists {
 57→            let git_ls_output = match vvc::vvce_git_command(&["ls-files", "--error-unmatch", file])
 58→                .output()
 59→            {
 60→                Ok(o) => o,
 61→                Err(e) => {
 62→                    vvco_err!(output, "jjx_notch: error: failed to check git tracking: {}", e);
 63→                    return (1, output.vvco_finish());
 64→                }
 65→            };
 66→
 67→            // If git ls-files fails, check if it's a staged deletion
 68→            if !git_ls_output.status.success() {
 69→                let git_diff_output = match vvc::vvce_git_command(&["diff", "--cached", "--name-only", "--diff-filter=D", "--", file])
 70→                    .output()
 71→                {
 72→                    Ok(o) => o,
 73→                    Err(e) => {
 74→                        vvco_err!(output, "jjx_notch: error: failed to check staged deletion: {}", e);
 75→                        return (1, output.vvco_finish());
 76→                    }
 77→                };
 78→
 79→                // If diff output is non-empty, file is a staged deletion - accept it
 80→                let is_staged_deletion = git_diff_output.status.success()
 81→                    && !git_diff_output.stdout.is_empty();
 82→
 83→                if !is_staged_deletion {
 84→                    vvco_err!(output, "jjx_notch: error: file does not exist and is not tracked by git: {}", file);
 85→                    return (1, output.vvco_finish());
 86→                }
 87→            }
 88→        }
 89→    }
 90→
 91→    // Parse identity - support both Coronet (5 chars) and Firemark (2 chars)
 92→    let identity = args.identity.strip_prefix(JJRF_CORONET_PREFIX).or_else(|| args.identity.strip_prefix(JJRF_FIREMARK_PREFIX)).unwrap_or(&args.identity);
 93→
 94→    let message = if identity.len() == 5 {
 95→        // Coronet - pace-affiliated commit
 96→        let coronet = match Coronet::jjrf_parse(&args.identity) {
 97→            Ok(c) => c,
 98→            Err(e) => {
 99→                vvco_err!(output, "jjx_notch: error: {}", e);
100→                return (1, output.vvco_finish());
101→            }
102→        };
103→        jjrn_format_notch_prefix(&coronet)
104→    } else if identity.len() == 2 {
105→        // Firemark - heat-only commit
106→        let firemark = match Firemark::jjrf_parse(&args.identity) {
107→            Ok(fm) => fm,
108→            Err(e) => {
109→                vvco_err!(output, "jjx_notch: error: {}", e);
110→                return (1, output.vvco_finish());
111→            }
112→        };
113→        let hallmark = vvc::vvcc_get_hallmark();
114→        let identity_str = format!("{}{}", JJRF_FIREMARK_PREFIX, firemark.jjrf_as_str());
115→        vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity_str, "n", "", None)
116→    } else {
117→        vvco_err!(output, "jjx_notch: error: identity must be Coronet (5 chars) or Firemark (2 chars), got {} chars", identity.len());
118→        return (1, output.vvco_finish());
119→    };
120→
121→    // Warn about uncommitted changes outside the file list
122→    let status_result = match vvc::vvce_git_command(&["status", "--porcelain"])
123→        .output()
124→    {
125→        Ok(o) => o,
126→        Err(e) => {
127→            vvco_err!(output, "jjx_notch: error: failed to run git status: {}", e);
128→            return (1, output.vvco_finish());
129→        }
130→    };
131→
132→    if !status_result.status.success() {
133→        vvco_err!(output, "jjx_notch: error: git status failed");
134→        return (1, output.vvco_finish());
135→    }
136→
137→    let status_output = String::from_utf8_lossy(&status_result.stdout);
138→    let files_set: HashSet<_> = args.files.iter().map(|s| s.as_str()).collect();
139→    let mut warnings = Vec::new();
140→
141→    for line in status_output.lines() {
142→        if line.len() < 4 {
143→            continue;
144→        }
145→        // Parse git status --porcelain format: "XY filename"
146→        let filepath = &line[3..];
147→        if !files_set.contains(filepath) {
148→            warnings.push(format!("  {}", line));
149→        }
150→    }
151→
152→    if !warnings.is_empty() {
153→        vvco_err!(output, "warning: uncommitted changes outside file list:");
154→        for warning in warnings {
155→            vvco_err!(output, "{}", warning);
156→        }
157→    }
158→
159→    // Stage only the specified files
160→    let mut git_add = vvc::vvce_git_command(&["add"]);
161→    for file in &args.files {
162→        git_add.arg(file);
163→    }
164→
165→    let add_output = match git_add.output() {
166→        Ok(o) => o,
167→        Err(e) => {
168→            vvco_err!(output, "jjx_notch: error: failed to run git add: {}", e);
169→            return (1, output.vvco_finish());
170→        }
171→    };
172→
173→    if !add_output.status.success() {
174→        vvco_err!(output, "jjx_notch: error: git add failed");
175→        return (1, output.vvco_finish());
176→    }
177→
178→    // Commit using vvc with the generated message prefix
179→    // If --intent provided, use it as the message; otherwise let haiku generate it
180→    let commit_args = if let Some(intent) = args.intent {
181→        vvc::vvcc_CommitArgs {
182→            prefix: None,
183→            message: Some(format!("{}{}", message, intent)),
184→            allow_empty: false,
185→            no_stage: true,  // We already staged above
186→            size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
187→            warn_limit: vvc::VVCG_WARN_LIMIT,
188→        }
189→    } else {
190→        vvc::vvcc_CommitArgs {
191→            prefix: Some(message),
192→            message: None,
193→            allow_empty: false,
194→            no_stage: true,  // We already staged above
195→            size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
196→            warn_limit: vvc::VVCG_WARN_LIMIT,
197→        }
198→    };
199→
200→    let rc = vvc::commit(&commit_args, &mut output);
201→    (rc, output.vvco_finish())
202→}
